<?php session_start(); if(!isset($_SESSION['idioma'])){ $_SESSION['idioma'] = 'es'; } if(isset($_GET['idioma'])){ $_SESSION['idioma'] = $_GET['idioma']; } $idioma['es']['inicio'] = "Inicio"; $idioma['es']['sobremi'] = "Sobre mi"; $idioma['es']['proyectos'] = "Proyectos"; $idioma['es']['contacto'] = "Contacto"; $idioma['en']['inicio'] = "Home"; $idioma['en']['sobremi'] = "About me"; $idioma['en']['proyectos'] = "Projects"; $idioma['en']['contacto'] = "Contact"; ?> <!doctype html> <html lang="es"> <head> <title>Multi idioma</title> <meta charset="utf-8"> <meta name="viewport" content="width=device-width, initial-scale=1"> <style> * { margin: 0; padding: 0; box-sizing: border-box; } body { font-family: Arial, sans-serif; background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); min-height: 100vh; padding: 20px; } header { display: flex; justify-content: space-between; align-items: center; background: white; padding: 20px 30px; border-radius: 10px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); margin-bottom: 30px; } h1 { color: #333; font-size: 28px; } select { padding: 8px 12px; border: 2px solid #667eea; border-radius: 5px; cursor: pointer; font-size: 16px; background: white; } select:hover { background: #f0f0f0; } nav { background: white; padding: 20px; border-radius: 10px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); } nav a { display: inline-block; margin: 10px 15px; color: #667eea; text-decoration: none; font-weight: bold; transition: 0.3s; } nav a:hover { color: #764ba2; transform: translateY(-2px); } .content { background: white; padding: 30px; border-radius: 10px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); max-width: 800px; margin: 0 auto; } .content h2 { color: #667eea; margin-bottom: 15px; } .content p { color: #666; line-height: 1.6; margin-bottom: 10px; } </style> </head> <body> <header> <h1>Andres Ramirez</h1> <select> <option value="es" <?php if($_SESSION['idioma'] == 'es'){echo 'selected';} ?>>🇪🇸 Español</option> <option value="en" <?php if($_SESSION['idioma'] == 'en'){echo 'selected';} ?>>🇬🇧 English</option> </select> </header> <nav> <a href="#"><?= $idioma[$_SESSION['idioma']]['inicio'] ?></a> <a href="#"><?= $idioma[$_SESSION['idioma']]['sobremi'] ?></a> <a href="#"><?= $idioma[$_SESSION['idioma']]['proyectos'] ?></a> <a href="#"><?= $idioma[$_SESSION['idioma']]['contacto'] ?></a> </nav> <div class="content"> <h2><?= $idioma[$_SESSION['idioma']]['sobremi'] ?></h2> <p><?= $_SESSION['idioma'] == 'es' ? 'Soy un desarrollador apasionado por la tecnología y la programación.' : 'I am a passionate developer interested in technology and programming.' ?></p> <p><?= $_SESSION['idioma'] == 'es' ? 'Con experiencia en múltiples lenguajes y frameworks.' : 'With experience in multiple languages and frameworks.' ?></p> </div> </body> <script> let selector = document.querySelector("select"); selector.onchange = function(){ window.location = "?idioma="+this.value; } </script> </html>